import json
from datasets import Dataset

def load(path: str, split: str = "val"):
    """
    读取 jsonl 文件（path），每行一个 JSON 对象。
    字段映射逻辑保持不变：
      problem <- example['question']
      answer  <- example.get('refined_standard_answer', '')
    """
    dataset = []
    with open(path, "r", encoding="utf-8") as f:
        for line_num, line in enumerate(f, 1):
            line = line.strip()
            if not line:
                continue
            try:
                example = json.loads(line)
            except json.JSONDecodeError as e:
                raise ValueError(f"JSONL 第 {line_num} 行解析失败: {e}\n内容: {line[:200]}") from e

            dataset.append({
                "problem": str(example["question"]),
                "answer": str(example.get("refined_standard_answer", "")),
            })

    return Dataset.from_list(dataset)
